import { execSync } from "child_process"; import fs from "fs"; import crypto from "crypto";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commit(name,str){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'depboth',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cb.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cb.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000}); }catch(e){ return 'EXC:'+e.message; } }
function deploy(id, name, b64, local){
  var code=Buffer.from(b64,'base64').toString('utf8');
  var cur=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/'+id+'"');
  var scope='global'; try{ scope=JSON.parse(cur).scope||'global'; }catch(e){}
  fs.writeFileSync('/tmp/p'+id+'.json', JSON.stringify({name:name, code:code, scope:scope, active:true}));
  exec('curl -sk -o /dev/null -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/p'+id+'.json "'+BASE+'/wp-json/code-snippets/v1/snippets/'+id+'"');
  var rb=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/'+id+'"');
  try{ var j=JSON.parse(rb); return {id:id,name:j.name,match:(crypto.createHash('md5').update(j.code||'','utf8').digest('hex')===local)}; }catch(e){ return {id:id,err:e.message}; }
}
(async()=>{
  var out=[];
  out.push(deploy(547,'Petshop Susidėjimo Rinkinio Vitrina v19','','b15ae6a68dcfedea8b9af59d338667df'));
  out.push(deploy(550,'Petshop Susidėjimo Rinkinio Kūrimo Forma v15','','9c024fa77625d97c3f4588b23264b0be'));
  commit('depboth_1782984814.json', JSON.stringify(out));
  console.log(JSON.stringify(out));
})();
